/* ==========================================================================
   ToggleButtonGroup — flush row of ToggleButton components
   ========================================================================== */

.group {
  display: inline-flex;
  align-items: stretch;
  border-radius: var(--dimension-radius-050);
  position: relative;
}

/* Inset ring / highlight overlay — sits above button children so it isn't
   covered by their backgrounds. Outset shadow stays on the element itself. */
.group::after {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: inherit;
  pointer-events: none;
}

/* ── Group-level elevation ──────────────────────────────────────────────── */
/* Individual item chrome (shadow/border) is suppressed via .item below.
   The group container carries the elevation so it wraps the whole control. */

/* Outset shadow on element; inset highlight on ::after (children would cover it otherwise) */
.groupElevated { box-shadow: var(--effect-shadow-elevated-sm); }
.groupElevated::after { box-shadow: var(--effect-highlight-elevated-sm); }

/* Flat ring lives entirely on ::after — same reasoning as highlight */
.groupFlat::after { box-shadow: inset 0 0 0 1px var(--color-border-tertiary); }

.groupFloating { box-shadow: var(--effect-shadow-elevated-floating); }
.groupFloating::after { box-shadow: var(--effect-highlight-elevated-floating); }
/* groupNone = ghost — no shadow, no border */

.groupRounded { border-radius: var(--dimension-radius-half); }

/* ── Base item ─────────────────────────────────────────────────────────────── */

.item {
  flex-shrink: 0;
  /* Suppress individual elevation so the group reads as one unit */
  box-shadow: none !important;
  /* Suppress noElevation individual border — divider handles separation */
  border: none !important;
  /* Suppress scale-on-press: transform would detach the divider from the
     adjacent button, creating a visible gap. Pressed state is still
     communicated via the ::after overlay colour. */
}
.item:active {
  transform: none !important;
}

/* ── Divider ────────────────────────────────────────────────────────────────
 * Rendered as a separate <div> between items so it is never part of any
 * button's stacking context — disabled (opacity: 0.5) or other state changes
 * on adjacent buttons cannot bleed through to the divider.
 * ─────────────────────────────────────────────────────────────────────────── */

/* Full-height divider (elevated / flat / floating).
 * Rendered as a separate element (independent of adjacent button opacity),
 * then nudged ±0.5px so it overlaps each neighbour and paints on top via
 * z-index — this lets the alpha token (rgb(0 0 0 / 0.1)) composite over
 * whatever fill the buttons carry (white, blue pressed state, etc.). */
.divider {
  width: 1px;
  flex-shrink: 0;
  background-color: var(--color-border-tertiary);
  position: relative;
  z-index: 1;
  margin: 0 -0.5px;
  pointer-events: none;
}

/* Ghost (elevation=none): short centred divider at icon height */
.dividerGhost    { height: 20px; align-self: center; } /* md default */
.dividerGhostXS  { height: 12px; }
.dividerGhostSM  { height: 16px; }

/* Ghost hover-fade: hide the divider on either side of a hovered ghost button */
.item:hover + .dividerGhost,
.dividerGhost:has(+ .item:hover) { opacity: 0; }

/* Ghost pressed-state: hide the divider on either side of a selected button */
.itemPressed + .dividerGhost,
.dividerGhost:has(+ .itemPressed) { opacity: 0; }


/* ── Ghost interaction states: rounded chips ──────────────────────────────────
 * Ghost items have no connecting chrome — hover/press overlay and selected
 * state always appear as independent rounded chips (4px on all corners).
 * Rounded groups: outer corners of first/last become pill; inner stay 4px.
 *
 * Uses explicit longhands throughout to avoid shorthand/longhand cascade
 * ordering ambiguity with the !important rules in .first / .last / .middle.
 * ─────────────────────────────────────────────────────────────────────────── */

/* ::after hover/press overlay — all positions: 4px all corners.
   Uses .group as ancestor (2-class specificity) to reliably beat
   .first / .last / .middle (1-class) regardless of load order. */
.group .itemShort::after {
  border-top-left-radius:     var(--dimension-radius-050) !important;
  border-top-right-radius:    var(--dimension-radius-050) !important;
  border-bottom-right-radius: var(--dimension-radius-050) !important;
  border-bottom-left-radius:  var(--dimension-radius-050) !important;
}

/* Selected chip — all positions: 4px all corners */
.group .itemPressed {
  border-top-left-radius:     var(--dimension-radius-050) !important;
  border-top-right-radius:    var(--dimension-radius-050) !important;
  border-bottom-right-radius: var(--dimension-radius-050) !important;
  border-bottom-left-radius:  var(--dimension-radius-050) !important;
}

/* ── Border radius: flatten only the inner-facing corners ──────────────────── */
/* Outer corners keep the button's own radius — works for default + rounded */

.first {
  border-top-right-radius:    0 !important;
  border-bottom-right-radius: 0 !important;
}

.last {
  border-top-left-radius:    0 !important;
  border-bottom-left-radius: 0 !important;
}

.middle {
  border-radius: 0 !important;
}

/* Rounded group: first — left corners become pill (3-class specificity) */
.groupRounded .first.itemShort::after,
.groupRounded .first.itemPressed {
  border-top-left-radius:    var(--dimension-radius-half) !important;
  border-bottom-left-radius: var(--dimension-radius-half) !important;
}

/* Rounded group: last — right corners become pill (3-class specificity) */
.groupRounded .last.itemShort::after,
.groupRounded .last.itemPressed {
  border-top-right-radius:    var(--dimension-radius-half) !important;
  border-bottom-right-radius: var(--dimension-radius-half) !important;
}

/* ── Rounded: inner-edge padding correction ────────────────────────────────── */
/*
 * Rounded buttons add `space-050` extra padding on each side.
 * In a group the inner-facing edge should use base (non-pill) padding instead.
 * XS rounded has no extra padding so needs no correction.
 */

/* MD — base padding: space-100 */
.roundedFirstMD { padding-right: var(--dimension-space-100) !important; }
.roundedLastMD  { padding-left:  var(--dimension-space-100) !important; }
.roundedMidMD   { padding-left:  var(--dimension-space-100) !important; padding-right: var(--dimension-space-100) !important; }

/* SM — base padding: space-075 */
.roundedFirstSM { padding-right: var(--dimension-space-075) !important; }
.roundedLastSM  { padding-left:  var(--dimension-space-075) !important; }
.roundedMidSM   { padding-left:  var(--dimension-space-075) !important; padding-right: var(--dimension-space-075) !important; }

import React from 'react';
import { cn } from '@/utils/cn';
import styles from './ToggleButtonGroup.module.css';

export interface ToggleButtonGroupProps {
  children: React.ReactNode;
  className?: string;
}

/**
 * Renders ToggleButton children flush side-by-side with a 1px divider between them.
 * Outer corners keep the button's own border-radius; inner corners are flattened.
 *
 * Individual button chrome (shadow/border) is suppressed — the group container
 * carries the elevation so it wraps the whole control as one visual unit.
 *
 * Divider behaviour by elevation:
 *   elevated / flat / floating — full-height color-border-tertiary line
 *   none (ghost)               — short centred line (icon/text height)
 *
 * Rounded groups: outer edges keep pill padding; inner edges revert to base padding.
 * Pressed state and onPressedChange are managed by the consumer on each ToggleButton.
 */
export const ToggleButtonGroup = ({ children, className }: ToggleButtonGroupProps) => {
  const items = React.Children.toArray(children).filter(React.isValidElement);
  const count = items.length;

  // Read elevation + rounded from first child to drive the group container style.
  const firstEl   = items[0] as React.ReactElement<Record<string, unknown>> | undefined;
  const firstProps = firstEl?.props as { elevation?: string; rounded?: boolean } | undefined;
  const groupElevation = firstProps?.elevation ?? 'elevated';
  const groupRounded   = !!firstProps?.rounded;
  const groupElevKey   = groupElevation.charAt(0).toUpperCase() + groupElevation.slice(1);

  return (
    <div
      className={cn(
        styles.group,
        (styles as Record<string, string>)[`group${groupElevKey}`],
        groupRounded && styles.groupRounded,
        className,
      )}
      role="group"
    >
      {items.map((child, i) => {
        const el = child as React.ReactElement<Record<string, unknown>>;
        const p = el.props as {
          className?: string;
          elevation?: string;
          size?: string;
          rounded?: boolean;
          pressed?: boolean;
          icon?: unknown;
          label?: unknown;
        };

        const isFirst = i === 0;
        const isLast  = i === count - 1;
        const isMid   = !isFirst && !isLast;

        const size       = (p.size ?? 'md') as 'xs' | 'sm' | 'md';
        const isRounded  = !!p.rounded;
        const isPressed  = !!p.pressed;
        const isIconOnly = !!p.icon && !p.label;
        // Ghost: elevation='none' (no chrome) → short centred divider
        const isGhost    = (p.elevation ?? 'elevated') === 'none';

        // XS rounded has no extra padding in ToggleButton so needs no correction
        const sizeKey = size.toUpperCase() as 'XS' | 'SM' | 'MD';
        const needsRoundedCorrection = isRounded && !isIconOnly && size !== 'xs';

        // Divider injected as a separate element so it's never affected by
        // the adjacent button's opacity (e.g. disabled state).
        const dividerClasses = cn(
          styles.divider,
          isGhost && styles.dividerGhost,
          isGhost && size === 'xs' && styles.dividerGhostXS,
          isGhost && size === 'sm' && styles.dividerGhostSM,
        );

        return (
          <React.Fragment key={i}>
            {i > 0 && <div className={dividerClasses} aria-hidden="true" />}
            {React.cloneElement(el, {
              className: cn(
                p.className,
                styles.item,
                isFirst && styles.first,
                isLast  && styles.last,
                isMid   && styles.middle,

                // Ghost variant: ::after overlay gets 4px radius treatment
                isGhost && styles.itemShort,

                // Ghost + pressed: selected state background chip
                isGhost && isPressed && styles.itemPressed,

                // Rounded: revert inner-edge padding to base (non-pill) value
                needsRoundedCorrection && isFirst && (styles as Record<string, string>)[`roundedFirst${sizeKey}`],
                needsRoundedCorrection && isLast  && (styles as Record<string, string>)[`roundedLast${sizeKey}`],
                needsRoundedCorrection && isMid   && (styles as Record<string, string>)[`roundedMid${sizeKey}`],
              ),
            })}
          </React.Fragment>
        );
      })}
    </div>
  );
};

ToggleButtonGroup.displayName = 'ToggleButtonGroup';
